// Config de búsqueda LinkedIn (guest API). Editá `searches` para cambiar keywords por BU.
// geoId 103644278 = United States. f_JT=C (Contract) + F (Freelance). f_WT=2 (Remote).
// f_TPR=r604800 = última semana. LinkedIn pagina de a 10 (start=0,10,20...).
const cfg = $json;
const geoId = cfg.geoId || '103644278';
const fJT = cfg.f_JT || 'C,F';
const fWT = cfg.f_WT || '';            // '' = cualquier modalidad; '2' = remote
const fTPR = cfg.f_TPR || 'r604800';
const searches = cfg.searches || [];

const base = 'https://www.linkedin.com/jobs-guest/jobs/api/seeMoreJobPostings/search';
const out = [];
for (const s of searches) {
  const term = typeof s === 'string' ? s : s.term;
  const pages = (typeof s === 'object' && s.pages) ? s.pages : (cfg.pages || 3);
  for (let p = 0; p < pages; p++) {
    const start = p * 10;
    const qs = new URLSearchParams({
      keywords: term,
      location: 'United States',
      geoId,
      f_JT: fJT,
      f_TPR: fTPR,
      start: String(start),
    });
    if (fWT) qs.set('f_WT', fWT);
    out.push({ json: { url: `${base}?${qs.toString()}`, term, start } });
  }
}
return out;

// Parsea las <li> del HTML del guest search → 1 item por job.
const items = $input.all();
const jobs = [];
const seen = new Set();
for (const it of items) {
  const term = it.json.term || null;
  const html = typeof it.json === 'string' ? it.json : (it.json.data || it.json.body || it.json.html || '');
  const text = typeof html === 'string' ? html : JSON.stringify(html);
  const cards = text.split('<li>').slice(1);
  for (const c of cards) {
    const idM = c.match(/urn:li:jobPosting:(\d+)/);
    const linkId = c.match(/jobs\/view\/[^"?]*?-(\d{7,})/);
    const id = (idM && idM[1]) || (linkId && linkId[1]);
    if (!id || seen.has(id)) continue;
    seen.add(id);
    const clean = (s) => s ? s.replace(/<[^>]+>/g,'').replace(/&amp;/g,'&').replace(/&#39;/g,"'").replace(/&quot;/g,'"').replace(/\s+/g,' ').trim() : null;
    const title = clean((c.match(/base-search-card__title">([\s\S]*?)<\/h3>/)||[])[1]);
    const company = clean((c.match(/base-search-card__subtitle">[\s\S]*?>([\s\S]*?)<\/a>/)||c.match(/base-search-card__subtitle">([\s\S]*?)<\/h4>/)||[])[1]);
    const location = clean((c.match(/job-search-card__location">([\s\S]*?)<\/span>/)||[])[1]);
    const posted = (c.match(/datetime="([^"]+)"/)||[])[1] || null;
    const linkM = c.match(/href="(https:\/\/www\.linkedin\.com\/jobs\/view\/[^"?]+)/);
    const companyUrl = (c.match(/href="(https:\/\/www\.linkedin\.com\/company\/[^"?]+)/)||[])[1] || null;
    jobs.push({ json: {
      linkedin_id: id,
      title: title || '(sin título)',
      company_name: company,
      company_url: companyUrl,
      location,
      link: linkM ? linkM[1] : `https://www.linkedin.com/jobs/view/${id}`,
      post_date: posted,
      matched_keyword: term,
      detail_url: `https://www.linkedin.com/jobs-guest/jobs/api/jobPosting/${id}`,
    }});
  }
}
return jobs;

// Corre 1 vez por job. Parsea el detalle, mapea a columnas de linkedin_jobs y filtra.
const meta = $('Parse cards').item.json;
const raw = $json;
const html = typeof raw === 'string' ? raw : (raw.data || raw.body || raw.html || '');
const text = typeof html === 'string' ? html : '';

const clean = (s) => s ? s.replace(/<[^>]+>/g,'').replace(/&amp;/g,'&').replace(/&#39;/g,"'").replace(/&quot;/g,'"').replace(/\s+/g,' ').trim() : null;

// criteria: Seniority level / Employment type / Job function / Industries
const crit = {};
const re = /description__job-criteria-subheader">([\s\S]*?)<\/h3>[\s\S]*?description__job-criteria-text[^>]*>([\s\S]*?)<\/span>/g;
let m;
while ((m = re.exec(text)) !== null) { crit[clean(m[1]).toLowerCase()] = clean(m[2]); }

const descM = text.match(/show-more-less-html__markup([\s\S]*?)<\/div>/);
const description = descM ? clean(descM[1]) : null;
const applicantsM = text.match(/num-applicants__caption">([\s\S]*?)</);
const applicants = applicantsM ? parseInt((applicantsM[1].match(/\d+/)||[])[0]||'',10) : null;

const employment = crit['employment type'] || null;   // Contract / Freelance / Full-time...
const seniority  = crit['seniority level'] || null;
const jobFunction = crit['job function'] || null;
const industry   = crit['industries'] || null;

// --- FILTRO: solo Contract/Freelance (objetivo 1099). Full-time/otros → fuera. ---
const ok = employment && /contract|freelance|temporary/i.test(employment);
if (!ok) return [];   // descartar acá (no llega al upsert)

const loc = meta.location || '';
const row = {
  linkedin_id: meta.linkedin_id,
  link: meta.link,
  title: meta.title,
  description,
  company_name: meta.company_name,
  company_url: meta.company_url,
  location: loc,
  country: /united states|usa|, [a-z]{2}$/i.test(loc) ? 'United States' : null,
  industry,
  employment_type: employment,
  workplace_type: null,
  seniority,
  job_function: jobFunction,
  applicants_count: Number.isFinite(applicants) ? applicants : null,
  posted_ago: null,
  post_date: meta.post_date,
  matched_keyword: meta.matched_keyword,

  raw_data: { search: meta, criteria: crit },
};
return [{ json: row }];
